public class IfStatement {
 public static void main(String[] args) {
 int age = 20;
 if (age >= 18) {
 System.out.println("You are eligible to vote");
 }
 }
}

public class SwitchStatement {
 public static void main(String[] args) {
 int day = 3;
 String dayName;
 switch (day) {
 case 1:
 dayName = "Monday";
 break;
 case 2:
 dayName = "Tuesday";
 break;
 case 3:
 dayName = "Wednesday";
 break;
 default:
 dayName = "Invalid day";
 }
 System.out.println(dayName);
 }
}

public class ForLoop {
 public static void main(String[] args) {
 for (int i = 1; i <= 10; i++) {
 System.out.println(i);
 }
 }
}
